import * as React from "react"
import { useState } from "react"
import { addPropertyControls, ControlType } from "framer"

// The full interactive 3D viewer (Three.js scene, pinned comments, shared storage UI, etc.)
// embedded as a self-contained HTML document. It's rendered in a sandboxed iframe via
// srcDoc so the popup stays fully functional without needing separate hosting.
const VIEWER_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\" />\n<title>3D Viewer Prototype</title>\n<style>\n  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Roboto:wght@300;400&family=Roboto+Flex:wght@400;500;600;700&display=swap');\n  @import url('https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:opsz,wght,FILL,GRAD@20..48,300..500,0..1,0');\n\n  .material-symbols-outlined{\n    font-family:'Material Symbols Outlined';font-weight:normal;font-style:normal;\n    font-size:20px;line-height:1;display:inline-block;\n    font-variation-settings:'FILL' 0,'wght' 350,'GRAD' 0,'opsz' 20;\n  }\n\n  :root{\n    --text-normal:#546881;\n    --text-heading:#3D4C5E;\n    --text-light:#828C99;\n    --text-lighter:#B2BBC6;\n    --surface-dark:#F6F8F9;\n    --surface-white:#FFFFFF;\n    --surface-light:#FCFDFD;\n    --violet:#7636D9;\n    --violet-light:#C1A5EE;\n    --completed:#00B894;\n    --submitted:#5A8DEE;\n    --shadow:0px 0px 4px rgba(0,0,0,0.16);\n  }\n  *{box-sizing:border-box;}\n  html,body{margin:0;height:100%;font-family:'Roboto Flex',sans-serif;color:var(--text-normal);}\n  body{\n    background:rgba(23,28,38,0.6);display:flex;align-items:center;justify-content:center;\n  }\n  #app{\n    display:flex;flex-direction:column;height:90vh;width:min(1500px,95vw);padding:10px;gap:10px;\n    background:var(--surface-dark);border-radius:16px;box-shadow:0 24px 64px rgba(0,0,0,0.4);position:relative;\n  }\n  .modal-close-btn{\n    position:absolute;top:-14px;right:-14px;width:32px;height:32px;border-radius:50%;border:none;\n    background:#fff;box-shadow:var(--shadow);display:flex;align-items:center;justify-content:center;\n    cursor:pointer;color:var(--text-normal);z-index:50;\n  }\n  .modal-close-btn:hover{color:var(--violet);}\n  .reopen-btn{\n    display:flex;align-items:center;gap:8px;background:#fff;border:none;border-radius:24px;\n    padding:12px 20px;box-shadow:var(--shadow);cursor:pointer;font-family:Inter,sans-serif;font-size:14px;\n    color:var(--text-normal);\n  }\n  .reopen-btn:hover{color:var(--violet);}\n\n  .topbar{\n    display:flex;align-items:center;justify-content:space-between;\n    padding:0 8px 10px 8px;border-bottom:1px solid var(--text-lighter);\n  }\n  .topbar .titles{display:flex;gap:24px;align-items:center;}\n  .topbar .titles .file{font-weight:600;font-size:16px;color:var(--text-normal);}\n  .topbar .titles .part{font-size:14px;color:var(--text-light);}\n  .you-box{display:flex;align-items:center;gap:8px;font-family:Inter,sans-serif;font-size:12px;color:var(--text-light);}\n  .you-box input{\n    border:1px solid var(--text-lighter);border-radius:4px;padding:4px 8px;font-size:12px;\n    font-family:Inter,sans-serif;color:var(--text-normal);width:110px;outline:none;\n  }\n  .you-box input:focus{border-color:var(--violet);}\n  .role-select{\n    border:1px solid var(--text-lighter);border-radius:4px;padding:4px 6px;font-size:11px;\n    font-family:Inter,sans-serif;color:var(--text-normal);background:#fff;outline:none;cursor:pointer;\n  }\n  .role-select:focus{border-color:var(--violet);}\n  .role-tag{\n    font-family:Inter,sans-serif;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.3px;\n    border-radius:8px;padding:1px 6px;\n  }\n  .role-tag.buyer{color:var(--completed);background:#E6F9F0;}\n  .role-tag.manufacturer{color:var(--violet);background:#F1E9FC;}\n  .comment-card .name-group{display:inline-flex;align-items:center;gap:6px;}\n  .comment-card.role-buyer{border-left:3px solid var(--completed);}\n  .comment-card.role-manufacturer{border-left:3px solid var(--violet);}\n  .thread-item.role-buyer{border-left:3px solid var(--completed);padding-left:6px;}\n  .thread-item.role-manufacturer{border-left:3px solid var(--violet);padding-left:6px;}\n\n  .rfq-box{display:flex;align-items:center;gap:8px;font-family:Inter,sans-serif;font-size:12px;color:var(--text-normal);}\n  .buyer-logo{\n    width:26px;height:26px;border-radius:50%;background-size:cover;background-position:center;\n    display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;color:#fff;\n    cursor:pointer;flex-shrink:0;box-shadow:var(--shadow);\n  }\n  .rfq-input{\n    border:1px solid transparent;border-radius:4px;padding:3px 6px;font-size:12px;font-family:Inter,sans-serif;\n    color:var(--text-normal);outline:none;background:transparent;\n  }\n  .rfq-input.buyer-name{font-weight:600;width:150px;}\n  .rfq-input.rfq-number{width:70px;font-family:'Roboto Flex',sans-serif;color:var(--violet);font-weight:600;}\n  .rfq-input:hover, .rfq-input:focus{border-color:var(--text-lighter);background:#fff;}\n  .rfq-label{color:var(--text-light);}\n  .rfq-divider{color:var(--text-lighter);}\n  .you-avatar{\n    width:22px;height:22px;border-radius:4px;display:flex;align-items:center;justify-content:center;\n    font-size:10px;font-weight:600;color:#fff;flex-shrink:0;\n  }\n\n  .main{flex:1;display:flex;gap:10px;min-height:0;}\n\n  .viewport-wrap{\n    position:relative;flex:1;border-radius:20px;overflow:hidden;background:#e8ecef;\n    box-shadow: inset 0 0 0 1px rgba(0,0,0,0.03);\n  }\n  canvas{display:block;width:100%;height:100%;touch-action:none;}\n  .viewport-wrap.add-mode canvas{cursor:crosshair;}\n\n  #pins-layer{position:absolute;inset:0;pointer-events:none;z-index:6;}\n  .pin{\n    position:absolute;width:38px;height:38px;transform:translate(-19px,-36px);\n    pointer-events:auto;cursor:pointer;\n    display:flex;align-items:flex-end;justify-content:center;\n  }\n  .pin .bubble{\n    min-width:27px;height:19px;border-radius:2px;padding:4px;box-sizing:border-box;position:relative;\n    display:flex;align-items:center;justify-content:center;box-shadow:var(--shadow);border:1px solid currentColor;\n  }\n  .pin .bubble span{font-size:12px;font-weight:400;font-family:'Roboto Flex',sans-serif;line-height:1;}\n  .pin.resolved .bubble{opacity:0.5;}\n  .pin.back-facing .bubble{opacity:0.35;}\n  .pin-resolved-badge{\n    position:absolute;bottom:-4px;right:-4px;background:var(--completed);color:#fff;border-radius:50%;\n    width:14px;height:14px;display:flex;align-items:center;justify-content:center;font-size:10px;line-height:1;\n  }\n  .pin.selected .bubble{\n    opacity:1;transform:scale(1.25);animation:pinGlow 1.3s ease-in-out infinite;position:relative;z-index:2;\n  }\n  @keyframes pinGlow{\n    0%,100%{box-shadow:0 0 0 0 rgba(118,54,217,0.55), var(--shadow);}\n    50%{box-shadow:0 0 0 8px rgba(118,54,217,0), var(--shadow);}\n  }\n  .pin.filter-match .bubble{opacity:1;transform:scale(1.2);box-shadow:0 0 0 4px rgba(118,54,217,0.35), var(--shadow);}\n  .pin.filter-dim .bubble{opacity:0.15;}\n\n  .toolbar{\n    position:absolute;left:50%;bottom:20px;transform:translateX(-50%);\n    display:flex;gap:8px;background:#fff;border-radius:12px;box-shadow:var(--shadow);padding:6px;\n  }\n  .tool-btn{\n    display:flex;flex-direction:column;align-items:center;gap:4px;padding:8px 12px;border-radius:8px;\n    border:none;background:transparent;cursor:pointer;font-family:Inter,sans-serif;font-size:11px;color:var(--text-normal);\n    min-width:56px;\n  }\n  .tool-btn:hover{background:var(--surface-dark);}\n  .tool-btn.active{background:#f1e9fc;color:var(--violet);}\n  .tool-btn .icon{font-size:18px;line-height:1;}\n  .tool-btn.disabled{opacity:0.45;cursor:not-allowed;}\n  .tool-btn.disabled:hover{background:transparent;}\n\n  .nav-widget{\n    position:absolute;top:16px;right:16px;display:flex;flex-direction:column;align-items:center;gap:8px;\n    pointer-events:auto;\n  }\n  .orbit-gizmo{\n    position:relative;width:72px;height:72px;background:#fff;border-radius:10px;box-shadow:var(--shadow);\n  }\n  .orbit-arrow{\n    position:absolute;border:none;background:transparent;color:var(--violet);cursor:pointer;\n    display:flex;align-items:center;justify-content:center;width:24px;height:24px;border-radius:6px;\n  }\n  .orbit-arrow:hover{background:#f1e9fc;}\n  .orbit-arrow.arrow-up{top:2px;left:24px;}\n  .orbit-arrow.arrow-down{bottom:2px;left:24px;}\n  .orbit-arrow.arrow-left{left:2px;top:24px;}\n  .orbit-arrow.arrow-right{right:2px;top:24px;}\n  .orbit-arrow.arrow-home{top:24px;left:24px;color:var(--text-light);}\n  .orbit-arrow.arrow-home .material-symbols-outlined{font-size:16px;}\n\n  .view-dropdown{position:relative;}\n  .view-toggle{\n    display:flex;flex-direction:column;align-items:center;gap:4px;background:#fff;border:none;border-radius:8px;\n    box-shadow:var(--shadow);padding:4px 8px;cursor:pointer;width:60px;\n  }\n  .view-toggle span:not(.material-symbols-outlined){\n    font-family:'Roboto Flex',sans-serif;font-size:12px;color:var(--text-normal);\n  }\n  .view-toggle .chevron{color:var(--text-normal);transition:transform 0.15s;}\n  .view-toggle:hover{background:var(--surface-dark);}\n  .view-toggle.open .chevron{transform:rotate(180deg);}\n  .cube-icon{display:block;}\n  .view-menu{\n    position:absolute;top:calc(100% + 6px);right:0;background:#fff;border-radius:8px;box-shadow:var(--shadow);\n    display:flex;flex-direction:column;min-width:110px;padding:4px;z-index:5;\n  }\n  .view-menu button{\n    border:none;background:transparent;text-align:left;padding:7px 10px;border-radius:6px;cursor:pointer;\n    font-family:Inter,sans-serif;font-size:12px;color:var(--text-normal);\n    display:flex;align-items:center;gap:8px;\n  }\n  .view-menu button .material-symbols-outlined{font-size:16px;color:var(--text-light);}\n  .view-menu button:hover{background:#f1e9fc;color:var(--violet);}\n  .view-menu button:hover .material-symbols-outlined{color:var(--violet);}\n\n  .brightness-control{\n    display:flex;align-items:center;gap:6px;background:#fff;border-radius:8px;box-shadow:var(--shadow);\n    padding:6px 10px;color:var(--text-normal);\n  }\n  .brightness-control input[type=\"range\"]{\n    width:60px;accent-color:var(--violet);cursor:pointer;\n  }\n\n  .compose{\n    position:absolute;width:240px;background:#fff;border:1px solid var(--violet-light);border-radius:8px;\n    box-shadow:var(--shadow);padding:10px;pointer-events:auto;font-family:Inter,sans-serif;\n  }\n  .compose textarea{\n    width:100%;min-height:56px;border:none;resize:none;outline:none;font-family:Inter,sans-serif;font-size:12px;\n    color:var(--text-normal);\n  }\n  .compose .row{display:flex;justify-content:flex-end;gap:8px;margin-top:6px;}\n  .compose button{\n    border:none;border-radius:4px;padding:5px 12px;font-size:12px;cursor:pointer;font-family:Inter,sans-serif;font-weight:500;\n  }\n  .compose .cancel{background:transparent;color:var(--text-light);}\n  .compose .post{background:var(--violet);color:#fff;}\n  .compose .post:disabled{background:var(--text-lighter);cursor:not-allowed;}\n\n  .thread-popup{\n    position:absolute;width:280px;max-height:360px;background:#fff;\n    border-radius:8px;box-shadow:var(--shadow);pointer-events:auto;display:flex;flex-direction:column;\n  }\n  .thread-popup .head{\n    display:flex;align-items:center;justify-content:space-between;padding:10px 12px;border-bottom:1px solid var(--text-normal);\n  }\n  .thread-popup .head span{font-weight:700;font-size:12px;color:var(--text-heading);font-family:'Roboto Flex',sans-serif;}\n  .thread-popup .head button{background:none;border:none;font-size:16px;color:var(--text-light);cursor:pointer;}\n  .thread-list{overflow-y:auto;padding:10px 12px;display:flex;flex-direction:column;gap:14px;}\n  .thread-item .top{display:flex;align-items:center;gap:10px;}\n  .delete-btn{\n    margin-left:4px;background:none;border:none;color:var(--text-lighter);cursor:pointer;\n    display:flex;align-items:center;padding:2px;border-radius:4px;\n  }\n  .delete-btn:hover{color:#d9455f;background:#fdecef;}\n  .delete-btn.confirming{color:#fff;background:#d9455f;}\n  .badge-avatar{\n    min-width:25px;height:17px;border-radius:2px;display:flex;align-items:center;justify-content:center;\n    font-size:12px;font-weight:400;font-family:'Roboto Flex',sans-serif;border:1px solid currentColor;\n    padding:0 4px;flex-shrink:0;box-sizing:border-box;\n  }\n  .thread-item .name{font-family:'Roboto Flex',sans-serif;font-weight:700;font-size:10px;color:var(--text-normal);}\n  .thread-item .time{font-family:Roboto,sans-serif;font-weight:300;font-size:8px;color:var(--text-normal);margin-left:auto;}\n  .thread-item .text{font-size:12px;line-height:1.4;margin:4px 0 0 35px;font-family:'Roboto Flex',sans-serif;color:var(--text-normal);}\n  .thread-reply{padding:0 12px 12px 12px;display:flex;flex-direction:column;gap:8px;}\n  .thread-reply-box{\n    border:1px solid var(--violet);border-radius:7px;padding:7px 9px;min-height:40px;display:flex;align-items:center;\n    position:relative;\n  }\n  .thread-reply-box input{\n    flex:1;border:none;outline:none;font-size:12px;font-family:'Roboto Flex',sans-serif;font-style:italic;color:var(--text-light);\n  }\n  .thread-reply-box input::placeholder{font-style:italic;color:var(--text-light);}\n  .thread-reply-actions{display:flex;align-items:center;justify-content:flex-end;}\n  .thread-reply-actions button{\n    border:none;background:var(--violet);color:#fff;border-radius:50px;width:40px;height:40px;cursor:pointer;\n    display:flex;align-items:center;justify-content:center;\n  }\n\n  .mention{color:var(--violet);font-weight:600;}\n  .mention-dropdown{\n    position:absolute;top:calc(100% + 2px);left:0;right:0;background:#fff;border-radius:6px;box-shadow:var(--shadow);\n    z-index:20;max-height:120px;overflow-y:auto;display:none;\n  }\n  .mention-option{padding:6px 10px;font-size:12px;font-family:Inter,sans-serif;cursor:pointer;color:var(--text-normal);}\n  .mention-option:hover{background:#f1e9fc;color:var(--violet);}\n\n  .reaction-bar{display:flex;gap:4px;margin:6px 0 0 35px;flex-wrap:wrap;}\n  .reaction-pill{\n    display:flex;align-items:center;gap:3px;background:var(--surface-dark);border:1px solid transparent;\n    border-radius:12px;padding:2px 7px;font-size:11px;cursor:pointer;font-family:Inter,sans-serif;color:var(--text-light);\n  }\n  .reaction-pill:hover{border-color:var(--text-lighter);}\n  .reaction-pill.mine{background:#f1e9fc;border-color:var(--violet);color:var(--violet);}\n\n  .edit-btn{\n    background:none;border:none;color:var(--text-lighter);cursor:pointer;display:flex;align-items:center;\n    padding:2px;border-radius:4px;\n  }\n  .edit-btn:hover{color:var(--violet);background:#f1e9fc;}\n  .edit-box{margin:4px 0 0 35px;display:flex;flex-direction:column;gap:6px;}\n  .edit-box textarea{\n    border:1px solid var(--violet);border-radius:6px;padding:6px 8px;font-size:12px;font-family:'Roboto Flex',sans-serif;\n    color:var(--text-normal);resize:none;min-height:44px;outline:none;\n  }\n  .edit-actions{display:flex;justify-content:flex-end;gap:6px;}\n  .edit-actions button{border:none;border-radius:4px;padding:4px 10px;font-size:11px;cursor:pointer;font-family:Inter,sans-serif;}\n  .edit-actions .edit-cancel{background:transparent;color:var(--text-light);}\n  .edit-actions .edit-save{background:var(--violet);color:#fff;}\n\n  .resolve-btn{background:none;border:none;color:var(--text-lighter);cursor:pointer;display:flex;align-items:center;padding:2px;}\n  .resolve-btn.resolved{color:var(--completed);}\n  .resolve-btn:hover{color:var(--completed);}\n\n  .sidebar{\n    width:220px;background:var(--surface-dark);border-radius:8px;padding:10px;display:flex;flex-direction:column;gap:10px;\n    overflow-y:auto;flex-shrink:0;\n  }\n  .sidebar-header{\n    font-weight:600;font-size:12px;text-align:center;padding-bottom:8px;border-bottom:1px solid var(--text-lighter);\n  }\n  .sidebar-header.row{display:flex;align-items:center;justify-content:space-between;text-align:left;}\n  .add-comment-btn{\n    display:flex;align-items:center;gap:4px;font-family:Inter,sans-serif;font-size:11px;font-weight:600;\n    color:var(--violet);background:#f1e9fc;border:none;border-radius:14px;padding:5px 10px;cursor:pointer;\n  }\n  .add-comment-btn:hover{background:#e6d9f9;}\n  .add-comment-btn.active{background:var(--violet);color:#fff;}\n  .empty-note{font-family:Inter,sans-serif;font-size:11px;color:var(--text-light);text-align:center;padding:20px 6px;}\n  .comment-card{\n    background:#fff;border:1px solid var(--violet-light);border-radius:4px;padding:8px;display:flex;flex-direction:column;gap:6px;\n    cursor:pointer;box-sizing:border-box;\n  }\n  .comment-card:hover{border-color:var(--violet);}\n  .comment-card.selected{\n    border:2px solid var(--violet);box-shadow:0 0 0 3px var(--violet-light);background:#faf7ff;\n  }\n  .comment-card.filter-match{border:2px solid var(--violet);background:#faf7ff;}\n  .comment-card.filter-dim{opacity:0.35;}\n  .comment-card .row1{display:flex;align-items:center;justify-content:space-between;gap:6px;}\n  .card-delete-btn{\n    margin-left:auto;background:none;border:none;color:var(--text-lighter);cursor:pointer;\n    display:flex;align-items:center;padding:2px;border-radius:4px;\n  }\n  .card-delete-btn:hover{color:#d9455f;background:#fdecef;}\n  .card-delete-btn.confirming{color:#fff;background:#d9455f;}\n  .part-tag{\n    font-family:Inter,sans-serif;font-size:10px;font-weight:600;color:var(--violet);\n    background:#f1e9fc;border-radius:10px;padding:2px 8px;\n  }\n  .resolved-chip{\n    font-family:Inter,sans-serif;font-size:10px;font-weight:600;color:var(--completed);\n    background:#e6f9f0;border-radius:10px;padding:2px 8px;display:flex;align-items:center;gap:2px;\n  }\n  .resolved-chip .material-symbols-outlined{font-size:12px;}\n  .comment-card.resolved{opacity:0.6;}\n  .comment-card .meta{display:flex;justify-content:space-between;align-items:baseline;}\n  .comment-card .name{font-family:Inter,sans-serif;font-weight:600;font-size:12px;}\n  .comment-card .time{font-family:Roboto,sans-serif;font-weight:300;font-size:9px;color:var(--text-light);}\n  .comment-card .snippet{\n    font-size:12px;line-height:1.3;color:var(--text-normal);\n    display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;\n  }\n  .comment-card .replies{font-size:11px;color:var(--submitted);}\n\n  .banner{\n    position:absolute;top:10px;left:50%;transform:translateX(-50%);background:rgba(84,104,129,0.92);color:#fff;\n    padding:6px 14px;border-radius:20px;font-family:Inter,sans-serif;font-size:11px;pointer-events:none;\n  }\n\n  .part-filter-panel{\n    position:absolute;top:16px;left:16px;display:flex;flex-direction:column;gap:6px;\n    background:#fff;border-radius:10px;box-shadow:var(--shadow);padding:6px;\n  }\n  .part-filter-btn{\n    border:none;background:transparent;border-radius:6px;padding:8px 14px;cursor:pointer;text-align:left;\n    font-family:Inter,sans-serif;font-size:12px;font-weight:500;color:var(--text-normal);white-space:nowrap;\n  }\n  .part-filter-btn:hover{background:var(--surface-dark);}\n  .part-filter-btn.active{background:var(--violet);color:#fff;}\n</style>\n</head>\n<body>\n<button id=\"reopenBtn\" class=\"reopen-btn\" style=\"display:none;\">\n  <span class=\"material-symbols-outlined\">view_in_ar</span>Reopen 3D Viewer\n</button>\n<div id=\"app\">\n  <button id=\"modalClose\" class=\"modal-close-btn\" title=\"Close\">\n    <span class=\"material-symbols-outlined\" style=\"font-size:18px;\">close</span>\n  </button>\n  <div class=\"topbar\">\n    <div class=\"titles\">\n      <span class=\"file\">Money Man</span>\n    </div>\n    <div class=\"rfq-box\">\n      <div class=\"buyer-logo\" id=\"buyerLogo\" title=\"Click to upload buyer logo\"></div>\n      <input type=\"file\" id=\"logoFileInput\" accept=\"image/*\" style=\"display:none\" />\n      <input id=\"buyerNameInput\" class=\"rfq-input buyer-name\" maxlength=\"28\" />\n      <span class=\"rfq-divider\">\u00b7</span>\n      <span class=\"rfq-label\">RFQ #</span>\n      <input id=\"rfqNumberInput\" class=\"rfq-input rfq-number\" maxlength=\"14\" />\n    </div>\n    <div class=\"you-box\">\n      Commenting as\n      <input id=\"nameInput\" maxlength=\"18\" />\n      <select id=\"roleSelect\" class=\"role-select\">\n        <option value=\"Buyer\">Buyer</option>\n        <option value=\"Manufacturer\">Manufacturer</option>\n      </select>\n      <div class=\"you-avatar\" id=\"youAvatar\"></div>\n    </div>\n  </div>\n\n  <div class=\"main\">\n    <div class=\"viewport-wrap\" id=\"viewportWrap\">\n      <canvas id=\"canvas\"></canvas>\n      <div id=\"pins-layer\"></div>\n      <div class=\"banner\" id=\"addModeBanner\" style=\"display:none;\">Click anywhere on the model to place a comment</div>\n      <div class=\"part-filter-panel\" id=\"partFilterPanel\">\n        <button class=\"part-filter-btn\" data-parts=\"Body\">Body</button>\n        <button class=\"part-filter-btn\" data-parts=\"Hat\">Hat</button>\n        <button class=\"part-filter-btn\" data-parts=\"Button 1,Button 2\">Buttons</button>\n        <button class=\"part-filter-btn\" data-parts=\"Monocle\">Monocle</button>\n        <button class=\"part-filter-btn\" data-parts=\"Moustache\">Moustache</button>\n      </div>\n\n      <div class=\"nav-widget\">\n        <div class=\"orbit-gizmo\" id=\"orbitGizmo\">\n          <button class=\"orbit-arrow arrow-up\" data-nudge=\"up\" title=\"Orbit up\"><span class=\"material-symbols-outlined\">keyboard_arrow_up</span></button>\n          <button class=\"orbit-arrow arrow-left\" data-nudge=\"left\" title=\"Orbit left\"><span class=\"material-symbols-outlined\">keyboard_arrow_left</span></button>\n          <button class=\"orbit-arrow arrow-home\" data-nudge=\"home\" title=\"Reset view\"><span class=\"material-symbols-outlined\">crop_free</span></button>\n          <button class=\"orbit-arrow arrow-right\" data-nudge=\"right\" title=\"Orbit right\"><span class=\"material-symbols-outlined\">keyboard_arrow_right</span></button>\n          <button class=\"orbit-arrow arrow-down\" data-nudge=\"down\" title=\"Orbit down\"><span class=\"material-symbols-outlined\">keyboard_arrow_down</span></button>\n        </div>\n        <div class=\"view-dropdown\">\n          <button class=\"view-toggle\" id=\"viewToggle\">\n            <svg class=\"cube-icon\" viewBox=\"0 0 26 22\" width=\"26\" height=\"22\" fill=\"none\">\n              <path d=\"M13 1 L24 6.5 L24 15.5 L13 21 L2 15.5 L2 6.5 Z\" stroke=\"#546881\" stroke-width=\"1.1\" stroke-linejoin=\"round\"/>\n              <path d=\"M2 6.5 L13 12 L24 6.5\" stroke=\"#546881\" stroke-width=\"1.1\" stroke-linejoin=\"round\"/>\n              <path d=\"M13 12 L13 21\" stroke=\"#546881\" stroke-width=\"1.1\"/>\n            </svg>\n            <span>View</span>\n            <span class=\"material-symbols-outlined chevron\" id=\"viewChevron\" style=\"font-size:16px;\">keyboard_arrow_up</span>\n          </button>\n          <div class=\"view-menu\" id=\"viewMenu\" style=\"display:none;\">\n            <button data-preset=\"iso\"><span class=\"material-symbols-outlined\">view_in_ar</span>Isometric</button>\n            <button data-preset=\"front\"><span class=\"material-symbols-outlined\">crop_square</span>Front</button>\n            <button data-preset=\"top\"><span class=\"material-symbols-outlined\">vertical_align_top</span>Top</button>\n            <button data-preset=\"right\"><span class=\"material-symbols-outlined\">arrow_forward</span>Right</button>\n          </div>\n        </div>\n        <div class=\"brightness-control\" title=\"Brightness\">\n          <span class=\"material-symbols-outlined\" style=\"font-size:16px;\">light_mode</span>\n          <input type=\"range\" id=\"brightnessSlider\" min=\"0.4\" max=\"2.2\" step=\"0.05\" value=\"1\" />\n        </div>\n      </div>\n\n      <div class=\"toolbar\">\n        <button class=\"tool-btn\" id=\"btnView\"><span class=\"material-symbols-outlined\">arrow_selector_tool</span>Select</button>\n        <button class=\"tool-btn disabled\" title=\"Coming soon\"><span class=\"material-symbols-outlined\">straighten</span>Measure</button>\n        <button class=\"tool-btn disabled\" title=\"Coming soon\"><span class=\"material-symbols-outlined\">view_in_ar</span>3D Type</button>\n        <button class=\"tool-btn\" id=\"btnComment\"><span class=\"material-symbols-outlined\">mode_comment</span>Comments</button>\n        <button class=\"tool-btn\" id=\"btnShot\"><span class=\"material-symbols-outlined\">photo_camera</span>Screenshot</button>\n        <button class=\"tool-btn disabled\" title=\"Coming soon\"><span class=\"material-symbols-outlined\">vertical_split</span>Section</button>\n        <button class=\"tool-btn disabled\" title=\"Coming soon\"><span class=\"material-symbols-outlined\">open_in_full</span>Explode</button>\n      </div>\n    </div>\n\n    <div class=\"sidebar\">\n      <div class=\"sidebar-header row\">\n        <span>Comments</span>\n        <button class=\"add-comment-btn\" id=\"btnAddComment\">\n          <span class=\"material-symbols-outlined\" style=\"font-size:16px;\">add_comment</span>Add comment\n        </button>\n      </div>\n      <div id=\"commentList\" style=\"display:flex;flex-direction:column;gap:10px;\"></div>\n    </div>\n  </div>\n</div>\n\n<script type=\"application/json\" id=\"modelData\">{\"Body\": {\"pos\": \"\", \"norm\": \"\", \"count\": 18204, \"centroid\": [0.24669562346843812, -0.36105981360730277, 0.0005196336784210855]}, \"Hat\": {\"pos\": \"\", \"norm\": \"\", \"count\": 8832, \"centroid\": [0.017825751762601434, 0.5606728070512569, -0.008580188004332846]}, \"Button 1\": {\"pos\": \"\", \"norm\": \"\", \"count\": 1980, \"centroid\": [0.5652129163043668, -0.8789029025068187, 0.00047828495370769744]}, \"Button 2\": {\"pos\": \"\", \"norm\": \"\", \"count\": 5802, \"centroid\": [0.568439078203607, -1.0473430569687205, 0.0004446571470507617]}, \"Monocle\": {\"pos\": \"\", \"norm\": \"\", \"count\": 4206, \"centroid\": [0.4700901502591907, 0.21836737308100299, -0.2581723692250773]}, \"Moustache\": {\"pos\": \"\", \"norm\": \"\", \"count\": 1884, \"centroid\": [0.5628170073032379, -0.03061624104583452, 0.0004937004489772765]}}</script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js\"></script>\n<script>\n(function(){\n  // ---------- palette / helpers ----------\n  const PALETTE = ['#7636D9','#00B894','#5A8DEE','#E8792B','#D9455F','#2FAF9E'];\n  const PALETTE_LIGHT = ['#FCFDFD','#E6F9F0','#EAF1FE','#FDEEE3','#FCEAEE','#E7F8F5'];\n  function hashIndex(str){\n    let h=0; for(let i=0;i<str.length;i++){h=str.charCodeAt(i)+((h<<5)-h);}\n    return Math.abs(h)%PALETTE.length;\n  }\n  function hashColor(str){ return PALETTE[hashIndex(str)]; }\n  function hashColorLight(str){ return PALETTE_LIGHT[hashIndex(str)]; }\n  function badgeStyle(str){ return `color:${hashColor(str)};background:${hashColorLight(str)};border-color:${hashColor(str)};`; }\n\n  const REACTIONS = ['\ud83d\udc4d','\u2764\ufe0f','\ud83d\udca1','\ud83d\udd27'];\n  function getAllAuthors(){\n    const set = new Set();\n    comments.forEach(c=>{ set.add(c.author); c.replies.forEach(r=>set.add(r.author)); });\n    return [...set];\n  }\n  function renderMentions(text){\n    const escaped = text.replace(/</g,'&lt;');\n    return escaped.replace(/@([A-Za-z][A-Za-z'-]*(?:\\s[A-Za-z][A-Za-z'-]*)?)/g, '<span class=\"mention\">@$1</span>');\n  }\n  function toggleReaction(item, emoji){\n    if(!item.reactions) item.reactions = {};\n    const list = item.reactions[emoji] || (item.reactions[emoji] = []);\n    const idx = list.indexOf(userName);\n    if(idx>=0) list.splice(idx,1); else list.push(userName);\n    if(list.length===0) delete item.reactions[emoji];\n    saveComments();\n  }\n  function renderReactionBar(item){\n    const reactions = item.reactions || {};\n    return `<div class=\"reaction-bar\">${REACTIONS.map(em=>{\n      const users = reactions[em] || [];\n      const mine = users.includes(userName);\n      return `<button class=\"reaction-pill${mine?' mine':''}\" data-emoji=\"${em}\">${em}${users.length? ' '+users.length : ''}</button>`;\n    }).join('')}</div>`;\n  }\n  function findItem(c, itemId, isRoot){\n    return isRoot ? c : c.replies.find(r=>r.id===itemId);\n  }\n  // native confirm()/alert() dialogs are blocked in this sandboxed environment,\n  // so destructive actions use a click-twice confirm instead.\n  function confirmedAction(btn, onConfirm){\n    if(btn.dataset.confirming === '1'){\n      clearTimeout(btn._confirmTimeout);\n      onConfirm();\n      return;\n    }\n    btn.dataset.confirming = '1';\n    btn.classList.add('confirming');\n    btn.title = 'Click again to confirm delete';\n    btn._confirmTimeout = setTimeout(()=>{\n      btn.dataset.confirming = '';\n      btn.classList.remove('confirming');\n      btn.title = 'Delete';\n    }, 2500);\n  }\n  function attachMentionAutocomplete(inputEl, dropdownEl){\n    if(!inputEl || !dropdownEl) return;\n    inputEl.addEventListener('input', ()=>{\n      const val = inputEl.value;\n      const caret = inputEl.selectionStart;\n      const match = val.slice(0, caret).match(/@([A-Za-z]*)$/);\n      if(match){\n        const query = match[1].toLowerCase();\n        const names = getAllAuthors().filter(a=>a!==userName && a.toLowerCase().includes(query));\n        if(names.length){\n          dropdownEl.innerHTML = names.slice(0,5).map(a=>`<div class=\"mention-option\" data-name=\"${a}\">${a}</div>`).join('');\n          dropdownEl.style.display='block';\n          return;\n        }\n      }\n      dropdownEl.style.display='none';\n    });\n    dropdownEl.addEventListener('mousedown', (e)=>{\n      const opt = e.target.closest('.mention-option');\n      if(!opt) return;\n      e.preventDefault();\n      const val = inputEl.value, caret = inputEl.selectionStart;\n      const newBefore = val.slice(0,caret).replace(/@([A-Za-z]*)$/, '@'+opt.dataset.name+' ');\n      inputEl.value = newBefore + val.slice(caret);\n      dropdownEl.style.display='none';\n      inputEl.focus();\n    });\n    inputEl.addEventListener('blur', ()=> setTimeout(()=>{ dropdownEl.style.display='none'; }, 150));\n  }\n  function initials(name){\n    const parts=name.trim().split(/\\s+/);\n    if(parts.length===1) return parts[0].slice(0,2).toUpperCase();\n    return (parts[0][0]+parts[1][0]).toUpperCase();\n  }\n  function roleLabel(role){\n    return role==='Manufacturer' ? 'MFG' : role;\n  }\n  function timeNow(){\n    return new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'});\n  }\n  function uid(){ return Math.random().toString(36).slice(2,10); }\n\n  // ---------- user identity (in-memory only, per session) ----------\n  let userName = 'Guest ' + Math.floor(1000+Math.random()*9000);\n  let userRole = 'Buyer';\n  const nameInput = document.getElementById('nameInput');\n  const youAvatar = document.getElementById('youAvatar');\n  const roleSelect = document.getElementById('roleSelect');\n  function refreshYou(){\n    nameInput.value = userName;\n    youAvatar.textContent = initials(userName);\n    youAvatar.style.background = hashColor(userName);\n    roleSelect.value = userRole;\n  }\n  nameInput.addEventListener('change', ()=>{ userName = nameInput.value.trim() || userName; refreshYou(); });\n  roleSelect.addEventListener('change', ()=>{ userRole = roleSelect.value; });\n  refreshYou();\n\n  // ---------- RFQ / buyer info (shared, visible to everyone on this viewer) ----------\n  let rfqMeta = { buyerName:'Ascension Manufacturing', rfqNumber:'24815', logo:null };\n  const buyerLogo = document.getElementById('buyerLogo');\n  const buyerNameInput = document.getElementById('buyerNameInput');\n  const rfqNumberInput = document.getElementById('rfqNumberInput');\n  const logoFileInput = document.getElementById('logoFileInput');\n\n  function refreshRfqUI(){\n    buyerNameInput.value = rfqMeta.buyerName;\n    rfqNumberInput.value = rfqMeta.rfqNumber;\n    if(rfqMeta.logo){\n      buyerLogo.style.backgroundImage = `url(${rfqMeta.logo})`;\n      buyerLogo.textContent = '';\n    } else {\n      buyerLogo.style.backgroundImage = 'none';\n      buyerLogo.textContent = initials(rfqMeta.buyerName);\n      buyerLogo.style.background = hashColor(rfqMeta.buyerName);\n    }\n  }\n  async function saveRfqMeta(){\n    try{ await window.storage.set('rfq-meta', JSON.stringify(rfqMeta), true); }catch(e){ console.error('rfq save failed', e); }\n  }\n  async function loadRfqMeta(){\n    try{\n      const res = await window.storage.get('rfq-meta', true);\n      if(res) rfqMeta = JSON.parse(res.value);\n    }catch(e){ /* keep defaults, first time using this viewer */ }\n    refreshRfqUI();\n    saveRfqMeta();\n  }\n  buyerNameInput.addEventListener('change', ()=>{\n    rfqMeta.buyerName = buyerNameInput.value.trim() || rfqMeta.buyerName;\n    refreshRfqUI(); saveRfqMeta();\n  });\n  rfqNumberInput.addEventListener('change', ()=>{\n    rfqMeta.rfqNumber = rfqNumberInput.value.trim() || rfqMeta.rfqNumber;\n    saveRfqMeta();\n  });\n  buyerLogo.addEventListener('click', ()=> logoFileInput.click());\n  logoFileInput.addEventListener('change', ()=>{\n    const file = logoFileInput.files[0];\n    if(!file) return;\n    const reader = new FileReader();\n    reader.onload = ()=>{\n      rfqMeta.logo = reader.result;\n      refreshRfqUI(); saveRfqMeta();\n    };\n    reader.readAsDataURL(file);\n  });\n\n  // ---------- three.js scene ----------\n  const canvas = document.getElementById('canvas');\n  const wrap = document.getElementById('viewportWrap');\n  const renderer = new THREE.WebGLRenderer({canvas, antialias:true, alpha:true});\n  renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));\n\n  const scene = new THREE.Scene();\n  const camera = new THREE.PerspectiveCamera(42, 1, 0.1, 100);\n\n  const hemiLight = new THREE.HemisphereLight(0xffffff, 0x8a95a3, 0.9);\n  scene.add(hemiLight);\n  const key = new THREE.DirectionalLight(0xffffff, 0.9);\n  key.position.set(4,6,5); scene.add(key);\n  const fill = new THREE.DirectionalLight(0xffffff, 0.35);\n  fill.position.set(-5,-2,-4); scene.add(fill);\n  const BASE_INTENSITY = { hemi:hemiLight.intensity, key:key.intensity, fill:fill.intensity };\n  function setBrightness(factor){\n    hemiLight.intensity = BASE_INTENSITY.hemi * factor;\n    key.intensity = BASE_INTENSITY.key * factor;\n    fill.intensity = BASE_INTENSITY.fill * factor;\n  }\n\n  // ---------- build the uploaded model from embedded per-group buffers ----------\n  const MODEL_DATA = JSON.parse(document.getElementById('modelData').textContent);\n  const partGroup = new THREE.Group();\n  const groupMeshes = {};\n\n  const PART_MATERIALS = {\n    'Body':      new THREE.MeshStandardMaterial({color:0x9aa4af, metalness:0.75, roughness:0.3}),\n    'Hat':       new THREE.MeshStandardMaterial({color:0x2b2f36, metalness:0.35, roughness:0.5}),\n    'Button 1':  new THREE.MeshStandardMaterial({color:0xd4af37, metalness:0.85, roughness:0.22}),\n    'Button 2':  new THREE.MeshStandardMaterial({color:0xd4af37, metalness:0.85, roughness:0.22}),\n    'Monocle':   new THREE.MeshPhysicalMaterial({color:0xcfe8ff, metalness:0.1, roughness:0.08, transparent:true, opacity:0.55}),\n    'Moustache': new THREE.MeshStandardMaterial({color:0x3b2a20, metalness:0.1, roughness:0.7}),\n  };\n  const DEFAULT_MATERIAL = new THREE.MeshStandardMaterial({color:0xb9c1c9, metalness:0.6, roughness:0.35});\n\n  function b64ToFloat32(b64){\n    const bin = atob(b64);\n    const bytes = new Uint8Array(bin.length);\n    for(let i=0;i<bin.length;i++) bytes[i] = bin.charCodeAt(i);\n    return new Float32Array(bytes.buffer);\n  }\n\n  Object.entries(MODEL_DATA).forEach(([name, g])=>{\n    const geo = new THREE.BufferGeometry();\n    geo.setAttribute('position', new THREE.BufferAttribute(b64ToFloat32(g.pos), 3));\n    geo.setAttribute('normal', new THREE.BufferAttribute(b64ToFloat32(g.norm), 3));\n    const mat = PART_MATERIALS[name] || DEFAULT_MATERIAL;\n    const mesh = new THREE.Mesh(geo, mat);\n    mesh.userData.partName = name;\n    mesh.userData.centroid = g.centroid;\n    partGroup.add(mesh);\n    groupMeshes[name] = mesh;\n  });\n\n  scene.add(partGroup);\n\n  // ---------- custom orbit / pan / zoom controls ----------\n  const target = new THREE.Vector3(0,0.1,0);\n  const spherical = {radius:4.4, theta:0.55, phi:1.3};\n  const DEFAULT_SPH = {...spherical};\n  function updateCamera(){\n    camera.position.set(\n      target.x + spherical.radius*Math.sin(spherical.phi)*Math.sin(spherical.theta),\n      target.y + spherical.radius*Math.cos(spherical.phi),\n      target.z + spherical.radius*Math.sin(spherical.phi)*Math.cos(spherical.theta)\n    );\n    camera.lookAt(target);\n  }\n  updateCamera();\n\n  let dragging=false, dragged=false, panMode=false, lastX=0, lastY=0;\n  canvas.addEventListener('contextmenu', e=>e.preventDefault());\n  canvas.addEventListener('pointerdown', e=>{\n    dragging=true; dragged=false; lastX=e.clientX; lastY=e.clientY;\n    panMode = e.button===2 || e.shiftKey;\n    canvas.setPointerCapture(e.pointerId);\n  });\n  canvas.addEventListener('pointermove', e=>{\n    if(!dragging) return;\n    const dx=e.clientX-lastX, dy=e.clientY-lastY;\n    if(Math.abs(dx)+Math.abs(dy) > 2) dragged=true;\n    if(panMode){\n      const panSpeed = spherical.radius*0.0016;\n      const right = new THREE.Vector3().setFromMatrixColumn(camera.matrix,0);\n      const up = new THREE.Vector3().setFromMatrixColumn(camera.matrix,1);\n      target.addScaledVector(right, -dx*panSpeed);\n      target.addScaledVector(up, dy*panSpeed);\n    } else {\n      spherical.theta -= dx*0.006;\n      spherical.phi = Math.min(Math.max(spherical.phi - dy*0.006, 0.15), Math.PI-0.15);\n    }\n    lastX=e.clientX; lastY=e.clientY;\n    updateCamera();\n  });\n  window.addEventListener('pointerup', e=>{\n    if(dragging && !dragged) handleClick(e);\n    dragging=false;\n  });\n  canvas.addEventListener('wheel', e=>{\n    e.preventDefault();\n    spherical.radius = Math.min(Math.max(spherical.radius*(1+e.deltaY*0.0012), 1.2), 12);\n    updateCamera();\n  }, {passive:false});\n\n  function resize(){\n    const w = wrap.clientWidth, h = wrap.clientHeight;\n    renderer.setSize(w,h,false);\n    camera.aspect = w/h;\n    camera.updateProjectionMatrix();\n    renderPins();\n  }\n  new ResizeObserver(resize).observe(wrap);\n\n  function animate(){\n    requestAnimationFrame(animate);\n    renderer.render(scene, camera);\n    renderPins();\n  }\n\n  // ---------- comments data ----------\n  let comments = [];\n  let addMode = false;\n  let openThreadId = null;\n  let editingItemId = null;\n  let activePartFilter = null; // array of part names currently highlighted, or null\n\n  function seedDefaults(){\n    const monocle = groupMeshes['Monocle'] ? groupMeshes['Monocle'].userData.centroid : [0,0,0];\n    const hat = groupMeshes['Hat'] ? groupMeshes['Hat'].userData.centroid : [0,0,0];\n    return [{\n      id: uid(), x:monocle[0], y:monocle[1], z:monocle[2], part:'Monocle',\n      author:'Riddhi Madeka', role:'Buyer', color: hashColor('Riddhi Madeka'), resolved:false, reactions:{},\n      text:'Can we thicken the monocle rim a bit? Feels fragile for printing at this scale.',\n      time:'6:30 pm',\n      replies:[{id:uid(), author:'Chris Vale', role:'Manufacturer', color: hashColor('Chris Vale'), reactions:{'\ud83d\udc4d':['Riddhi Madeka']}, text:'Agreed \u2014 bumping rim thickness in the next rev.', time:'6:41 pm'}]\n    },{\n      id: uid(), x:hat[0], y:hat[1], z:hat[2], part:'Hat',\n      author:'Chris Vale', role:'Manufacturer', color: hashColor('Chris Vale'), resolved:true, reactions:{'\u2764\ufe0f':['Riddhi Madeka']},\n      text:'Love the brim detail on the hat @Riddhi Madeka \u2014 clean read from every angle.',\n      time:'6:52 pm',\n      replies:[]\n    }];\n  }\n\n  function normalizeComments(list){\n    if(!Array.isArray(list)) return [];\n    return list.filter(c=>c && typeof c==='object').map(c=>({\n      id: c.id || uid(),\n      x: typeof c.x==='number' && !isNaN(c.x) ? c.x : 0,\n      y: typeof c.y==='number' && !isNaN(c.y) ? c.y : 0,\n      z: typeof c.z==='number' && !isNaN(c.z) ? c.z : 0,\n      part: c.part || null,\n      author: c.author || 'Unknown',\n      role: c.role || null,\n      color: c.color || hashColor(c.author || 'Unknown'),\n      text: typeof c.text==='string' ? c.text : '',\n      time: c.time || '',\n      resolved: !!c.resolved,\n      reactions: (c.reactions && typeof c.reactions==='object') ? c.reactions : {},\n      replies: Array.isArray(c.replies) ? c.replies.filter(r=>r && typeof r==='object').map(r=>({\n        id: r.id || uid(),\n        author: r.author || 'Unknown',\n        role: r.role || null,\n        color: r.color || hashColor(r.author || 'Unknown'),\n        text: typeof r.text==='string' ? r.text : '',\n        time: r.time || '',\n        reactions: (r.reactions && typeof r.reactions==='object') ? r.reactions : {}\n      })) : []\n    }));\n  }\n\n  async function loadComments(){\n    try{\n      const res = await window.storage.get('viewer-comments', true);\n      comments = res ? normalizeComments(JSON.parse(res.value)) : seedDefaults();\n    }catch(e){\n      comments = seedDefaults();\n    }\n    if(!comments.length){ comments = seedDefaults(); }\n    renderList();\n    renderPins();\n    saveComments();\n  }\n  async function saveComments(){\n    try{ await window.storage.set('viewer-comments', JSON.stringify(comments), true); }catch(e){ console.error('storage save failed', e); }\n  }\n  // poll for updates from other users\n  setInterval(async ()=>{\n    if(document.querySelector('.compose')) return; // don't clobber an open compose box\n    try{\n      const res = await window.storage.get('viewer-comments', true);\n      if(res){\n        const normalized = normalizeComments(JSON.parse(res.value));\n        const incoming = JSON.stringify(normalized);\n        if(incoming !== JSON.stringify(comments)){\n          comments = normalized;\n          renderList();\n          renderPins();\n        }\n      }\n    }catch(e){}\n    if(document.activeElement===buyerNameInput || document.activeElement===rfqNumberInput) return;\n    try{\n      const res2 = await window.storage.get('rfq-meta', true);\n      if(res2){\n        const incoming2 = JSON.stringify(JSON.parse(res2.value));\n        if(incoming2 !== JSON.stringify(rfqMeta)){\n          rfqMeta = JSON.parse(incoming2);\n          refreshRfqUI();\n        }\n      }\n    }catch(e){}\n  }, 4000);\n\n  // ---------- raycasting / add comment ----------\n  const raycaster = new THREE.Raycaster();\n  const mouseNDC = new THREE.Vector2();\n  let pendingPart = null;\n  function handleClick(e){\n    const rect = canvas.getBoundingClientRect();\n    mouseNDC.x = ((e.clientX-rect.left)/rect.width)*2-1;\n    mouseNDC.y = -((e.clientY-rect.top)/rect.height)*2+1;\n    raycaster.setFromCamera(mouseNDC, camera);\n    const hits = raycaster.intersectObjects(partGroup.children);\n    if(!hits.length) return;\n    if(addMode){\n      pendingPart = hits[0].object.userData.partName || null;\n      const p = hits[0].point;\n      openCompose(p, e.clientX, e.clientY);\n      return;\n    }\n    // not adding a comment: if the click landed near an existing comment's\n    // marked spot on the surface, open that comment right here.\n    const hitPoint = hits[0].point;\n    let closest = null, closestDist = Infinity;\n    comments.forEach(c=>{\n      const d = hitPoint.distanceTo(new THREE.Vector3(c.x,c.y,c.z));\n      if(d < closestDist){ closestDist = d; closest = c; }\n    });\n    const HIT_RADIUS = 0.18; // world units \u2014 tuned to the model's normalized ~2.6 unit scale\n    if(closest && closestDist < HIT_RADIUS){\n      const v = new THREE.Vector3(closest.x, closest.y, closest.z).project(camera);\n      const r = wrap.getBoundingClientRect();\n      openThread(closest.id, (v.x*0.5+0.5)*r.width, (-v.y*0.5+0.5)*r.height);\n    }\n  }\n\n  function openCompose(point, clientX, clientY){\n    document.querySelectorAll('.compose,.thread-popup').forEach(n=>n.remove());\n    const rect = wrap.getBoundingClientRect();\n    const box = document.createElement('div');\n    box.className='compose';\n    let left = clientX-rect.left+12, top = clientY-rect.top-10;\n    left = Math.min(left, rect.width-252); top = Math.max(top,10);\n    box.style.left = left+'px'; box.style.top = top+'px';\n    box.innerHTML = `<textarea placeholder=\"Add a comment\u2026 (@ to mention)\" autofocus></textarea>\n      <div class=\"mention-dropdown\"></div>\n      <div class=\"row\"><button class=\"cancel\">Cancel</button><button class=\"post\" disabled>Post</button></div>`;\n    wrap.appendChild(box);\n    const ta = box.querySelector('textarea'), postBtn = box.querySelector('.post');\n    ta.focus();\n    ta.addEventListener('input', ()=>{ postBtn.disabled = !ta.value.trim(); });\n    attachMentionAutocomplete(ta, box.querySelector('.mention-dropdown'));\n    box.querySelector('.cancel').addEventListener('click', ()=>box.remove());\n    postBtn.addEventListener('click', ()=>{\n      const c = {\n        id:uid(), x:point.x, y:point.y, z:point.z, part:pendingPart,\n        author:userName, role:userRole, color:hashColor(userName), text:ta.value.trim(),\n        time:timeNow(), replies:[], resolved:false, reactions:{}\n      };\n      comments.push(c);\n      saveComments(); renderList(); renderPins();\n      box.remove();\n      setAddMode(false);\n      const v = point.clone().project(camera);\n      const rect = wrap.getBoundingClientRect();\n      openThread(c.id, (v.x*0.5+0.5)*rect.width, (-v.y*0.5+0.5)*rect.height);\n    });\n  }\n\n  // ---------- pins ----------\n  const pinsLayer = document.getElementById('pins-layer');\n  const occlusionRaycaster = new THREE.Raycaster();\n  function isOccluded(point){\n    const camPos = camera.position;\n    const dir = new THREE.Vector3().subVectors(point, camPos);\n    const dist = dir.length();\n    dir.normalize();\n    occlusionRaycaster.set(camPos, dir);\n    occlusionRaycaster.near = 0.01;\n    occlusionRaycaster.far = Math.max(dist - 0.03, 0.02);\n    return occlusionRaycaster.intersectObjects(partGroup.children).length > 0;\n  }\n\n  const pinElements = new Map(); // comment id -> persistent pin DOM element\n  function renderPins(){\n    const rect = wrap.getBoundingClientRect();\n    const seen = new Set();\n    comments.forEach(c=>{\n      seen.add(c.id);\n      const point = new THREE.Vector3(c.x,c.y,c.z);\n      const v = point.clone().project(camera);\n      let pin = pinElements.get(c.id);\n      if(v.z>1){\n        if(pin) pin.style.display='none';\n        return;\n      }\n      if(!pin){\n        pin = document.createElement('div');\n        pin.addEventListener('click', (ev)=>{\n          ev.stopPropagation();\n          const left = parseFloat(pin.style.left), top = parseFloat(pin.style.top);\n          openThread(c.id, left, top);\n        });\n        pinsLayer.appendChild(pin);\n        pinElements.set(c.id, pin);\n      }\n      const x = (v.x*0.5+0.5)*rect.width;\n      const y = (-v.y*0.5+0.5)*rect.height;\n      const backFacing = isOccluded(point);\n      pin.style.display = '';\n      pin.style.left = x+'px'; pin.style.top = y+'px';\n      const filterMatch = activePartFilter && activePartFilter.includes(c.part);\n      const filterDim = activePartFilter && !filterMatch;\n      pin.className = 'pin'+(openThreadId===c.id?' selected':'')+(c.resolved?' resolved':'')+(backFacing?' back-facing':'')+(filterMatch?' filter-match':'')+(filterDim?' filter-dim':'');\n      pin.innerHTML = `<div class=\"bubble\" style=\"${badgeStyle(c.author)}\"><span>${initials(c.author)}</span>${c.resolved?'<span class=\"pin-resolved-badge\"><span class=\"material-symbols-outlined\" style=\"font-size:10px;\">check</span></span>':''}</div>`;\n    });\n    pinElements.forEach((el, id)=>{\n      if(!seen.has(id)){ el.remove(); pinElements.delete(id); }\n    });\n  }\n\n  function threadItemHTML(it){\n    const editing = editingItemId === it.id;\n    const canEdit = it.author === userName;\n    const roleClass = it.role ? ' role-'+it.role.toLowerCase() : '';\n    return `\n      <div class=\"thread-item${roleClass}\" data-item-id=\"${it.id}\" data-is-root=\"${it.isRoot}\">\n        <div class=\"top\">\n          <div class=\"badge-avatar\" style=\"${badgeStyle(it.author)}\">${initials(it.author)}</div>\n          <span class=\"name\">${it.author}</span>\n          ${it.role? `<span class=\"role-tag ${it.role.toLowerCase()}\">${roleLabel(it.role)}</span>`:''}\n          <span class=\"time\">${it.time}</span>\n          ${!editing && canEdit? `<button class=\"edit-btn\" title=\"Edit\"><span class=\"material-symbols-outlined\" style=\"font-size:15px;\">edit</span></button>` : ''}\n          ${!editing? `<button class=\"delete-btn\" title=\"Delete\"><span class=\"material-symbols-outlined\" style=\"font-size:15px;\">delete</span></button>` : ''}\n        </div>\n        ${editing ? `\n          <div class=\"edit-box\">\n            <textarea class=\"edit-textarea\">${it.text.replace(/</g,'&lt;')}</textarea>\n            <div class=\"edit-actions\">\n              <button class=\"edit-cancel\">Cancel</button>\n              <button class=\"edit-save\">Save</button>\n            </div>\n          </div>\n        ` : `\n          <div class=\"text\">${renderMentions(it.text)}</div>\n          ${renderReactionBar(it)}\n        `}\n      </div>`;\n  }\n\n  function openThread(id, x, y){\n    document.querySelectorAll('.compose,.thread-popup').forEach(n=>n.remove());\n    openThreadId = id;\n    renderList();\n    const c = comments.find(cm=>cm.id===id);\n    if(!c) return;\n    const rect = wrap.getBoundingClientRect();\n    const pop = document.createElement('div');\n    pop.className='thread-popup';\n    let left = Math.min(x+16, rect.width-292);\n    let top = Math.min(Math.max(y-40,10), rect.height-350);\n    pop.style.left=left+'px'; pop.style.top=top+'px';\n\n    const allItems = [{...c, isRoot:true}, ...c.replies.map(r=>({...r, isRoot:false}))];\n    pop.innerHTML = `\n      <div class=\"head\">\n        <span>Comments</span>\n        <button class=\"close\"><span class=\"material-symbols-outlined\" style=\"font-size:16px;\">close</span></button>\n      </div>\n      <div class=\"thread-list\">\n        ${allItems.map(threadItemHTML).join('')}\n      </div>\n      <div class=\"thread-reply\">\n        <div class=\"thread-reply-box\"><input placeholder=\"Reply (@ to mention)\" /><div class=\"mention-dropdown\"></div></div>\n        <div class=\"thread-reply-actions\">\n          <button><span class=\"material-symbols-outlined\" style=\"font-size:18px;\">send</span></button>\n        </div>\n      </div>\n    `;\n    wrap.appendChild(pop);\n\n    pop.querySelector('.close').addEventListener('click', ()=>{ pop.remove(); openThreadId=null; editingItemId=null; renderPins(); renderList(); });\n\n    pop.querySelectorAll('.delete-btn').forEach(btn=>{\n      btn.addEventListener('click', (ev)=>{\n        ev.stopPropagation();\n        const item = btn.closest('.thread-item');\n        const itemId = item.dataset.itemId;\n        const isRoot = item.dataset.isRoot === 'true';\n        confirmedAction(btn, ()=>{\n          if(isRoot){\n            comments = comments.filter(cm=>cm.id!==id);\n            openThreadId = null;\n            saveComments(); renderList(); renderPins();\n            pop.remove();\n          } else {\n            c.replies = c.replies.filter(r=>r.id!==itemId);\n            saveComments(); renderList();\n            pop.remove(); openThread(id, x, y);\n          }\n        });\n      });\n    });\n\n    pop.querySelectorAll('.edit-btn').forEach(btn=>{\n      btn.addEventListener('click', ()=>{\n        editingItemId = btn.closest('.thread-item').dataset.itemId;\n        pop.remove(); openThread(id, x, y);\n      });\n    });\n    pop.querySelectorAll('.edit-cancel').forEach(btn=>{\n      btn.addEventListener('click', ()=>{ editingItemId=null; pop.remove(); openThread(id, x, y); });\n    });\n    pop.querySelectorAll('.edit-save').forEach(btn=>{\n      btn.addEventListener('click', ()=>{\n        const item = btn.closest('.thread-item');\n        const itemId = item.dataset.itemId, isRoot = item.dataset.isRoot==='true';\n        const newText = item.querySelector('.edit-textarea').value.trim();\n        if(newText){ findItem(c, itemId, isRoot).text = newText; saveComments(); renderList(); }\n        editingItemId = null;\n        pop.remove(); openThread(id, x, y);\n      });\n    });\n\n    pop.querySelectorAll('.reaction-pill').forEach(btn=>{\n      btn.addEventListener('click', ()=>{\n        const item = btn.closest('.thread-item');\n        const itemId = item.dataset.itemId, isRoot = item.dataset.isRoot==='true';\n        toggleReaction(findItem(c, itemId, isRoot), btn.dataset.emoji);\n        renderList();\n        pop.remove(); openThread(id, x, y);\n      });\n    });\n\n    const input = pop.querySelector('.thread-reply-box input');\n    attachMentionAutocomplete(input, pop.querySelector('.mention-dropdown'));\n    const sendReply = ()=>{\n      const txt = input.value.trim(); if(!txt) return;\n      c.replies.push({id:uid(), author:userName, role:userRole, color:hashColor(userName), text:txt, time:timeNow(), reactions:{}});\n      saveComments(); renderList();\n      pop.remove(); openThread(id, x, y);\n    };\n    pop.querySelector('.thread-reply-actions button').addEventListener('click', sendReply);\n    input.addEventListener('keydown', e=>{ if(e.key==='Enter') sendReply(); });\n  }\n\n  document.addEventListener('click', (e)=>{\n    if(!e.target.closest('.thread-popup') && !e.target.closest('.pin') && !e.target.closest('.comment-card')){\n      document.querySelectorAll('.thread-popup').forEach(n=>n.remove());\n      openThreadId = null;\n      renderList();\n    }\n  });\n\n  // ---------- sidebar list ----------\n  const listEl = document.getElementById('commentList');\n  function renderList(){\n    if(!comments.length){\n      listEl.innerHTML = `<div class=\"empty-note\">No comments yet. Turn on Comment mode and click the part to leave one \u2014 everyone viewing this prototype will see it.</div>`;\n      return;\n    }\n    listEl.innerHTML = comments.map(c=>{\n      const filterMatch = activePartFilter && activePartFilter.includes(c.part);\n      const filterDim = activePartFilter && !filterMatch;\n      return `\n      <div class=\"comment-card${c.resolved?' resolved':''}${openThreadId===c.id?' selected':''}${c.role?' role-'+c.role.toLowerCase():''}${filterMatch?' filter-match':''}${filterDim?' filter-dim':''}\" data-id=\"${c.id}\">\n        <div class=\"row1\">\n          <div class=\"badge-avatar\" style=\"${badgeStyle(c.author)}\">${initials(c.author)}</div>\n          ${c.part? `<span class=\"part-tag\">${c.part}</span>`:''}\n          ${c.resolved? `<span class=\"resolved-chip\"><span class=\"material-symbols-outlined\">check_circle</span>Resolved</span>`:''}\n          <button class=\"card-delete-btn\" title=\"Delete comment\"><span class=\"material-symbols-outlined\" style=\"font-size:15px;\">delete</span></button>\n        </div>\n        <div class=\"meta\"><span class=\"name-group\"><span class=\"name\">${c.author}</span>${c.role? `<span class=\"role-tag ${c.role.toLowerCase()}\">${roleLabel(c.role)}</span>`:''}</span><span class=\"time\">${c.time}</span></div>\n        <div class=\"snippet\">${renderMentions(c.text)}</div>\n        <div class=\"reaction-bar\" style=\"margin-left:0;\">${REACTIONS.map(em=>{\n          const users=(c.reactions&&c.reactions[em])||[]; const mine=users.includes(userName);\n          return `<button class=\"reaction-pill${mine?' mine':''}\" data-emoji=\"${em}\">${em}${users.length? ' '+users.length:''}</button>`;\n        }).join('')}</div>\n        ${c.replies.length? `<div class=\"replies\">${c.replies.length} ${c.replies.length===1?'Reply':'Replies'}</div>`:''}\n      </div>`;\n    }).join('');\n    listEl.querySelectorAll('.card-delete-btn').forEach(btn=>{\n      btn.addEventListener('click', (ev)=>{\n        ev.stopPropagation();\n        const id = btn.closest('.comment-card').dataset.id;\n        confirmedAction(btn, ()=>{\n          comments = comments.filter(cm=>cm.id!==id);\n          saveComments(); renderList(); renderPins();\n          if(openThreadId===id){\n            document.querySelectorAll('.thread-popup').forEach(n=>n.remove());\n            openThreadId=null;\n          }\n        });\n      });\n    });\n    listEl.querySelectorAll('.comment-card .reaction-pill').forEach(btn=>{\n      btn.addEventListener('click', (ev)=>{\n        ev.stopPropagation();\n        const c = comments.find(cm=>cm.id===btn.closest('.comment-card').dataset.id);\n        toggleReaction(c, btn.dataset.emoji);\n        renderList();\n      });\n    });\n    listEl.querySelectorAll('.comment-card').forEach(card=>{\n      card.addEventListener('click', (e)=>{\n        e.stopPropagation();\n        const c = comments.find(cm=>cm.id===card.dataset.id);\n        const v = new THREE.Vector3(c.x,c.y,c.z).project(camera);\n        const rect = wrap.getBoundingClientRect();\n        const x=(v.x*0.5+0.5)*rect.width, y=(-v.y*0.5+0.5)*rect.height;\n        openThread(c.id, x, y);\n      });\n    });\n    const selectedCard = listEl.querySelector('.comment-card.selected');\n    if(selectedCard) selectedCard.scrollIntoView({behavior:'smooth', block:'nearest'});\n  }\n\n  // ---------- toolbar ----------\n  const btnComment = document.getElementById('btnComment');\n  const btnAddComment = document.getElementById('btnAddComment');\n  const addModeBanner = document.getElementById('addModeBanner');\n\n  function setAddMode(on){\n    addMode = on;\n    btnComment.classList.toggle('active', addMode);\n    btnAddComment.classList.toggle('active', addMode);\n    wrap.classList.toggle('add-mode', addMode);\n    addModeBanner.style.display = addMode ? 'block' : 'none';\n  }\n\n  document.getElementById('btnView').addEventListener('click', (e)=>{\n    Object.assign(spherical, DEFAULT_SPH); target.set(0,0,0); updateCamera();\n    setAddMode(false);\n    e.currentTarget.classList.add('active');\n    setTimeout(()=>e.currentTarget.classList.remove('active'), 200);\n  });\n  btnComment.addEventListener('click', ()=> setAddMode(!addMode));\n  btnAddComment.addEventListener('click', ()=> setAddMode(!addMode));\n  document.getElementById('btnShot').addEventListener('click', ()=>{\n    renderer.render(scene, camera);\n    const link = document.createElement('a');\n    link.download = 'viewer-screenshot.png';\n    link.href = canvas.toDataURL('image/png');\n    link.click();\n  });\n\n  // ---------- orbit gizmo (nudge buttons) ----------\n  const NUDGE = 0.45;\n  document.querySelectorAll('.orbit-arrow').forEach(btn=>{\n    btn.addEventListener('click', ()=>{\n      const dir = btn.dataset.nudge;\n      if(dir==='home'){ Object.assign(spherical, DEFAULT_SPH); target.set(0,0.1,0); }\n      if(dir==='up')    spherical.phi = Math.max(spherical.phi - NUDGE, 0.15);\n      if(dir==='down')  spherical.phi = Math.min(spherical.phi + NUDGE, Math.PI-0.15);\n      if(dir==='left')  spherical.theta -= NUDGE;\n      if(dir==='right') spherical.theta += NUDGE;\n      updateCamera();\n    });\n  });\n\n  // ---------- view dropdown ----------\n  const VIEW_PRESETS = {\n    iso:   {theta:0.55, phi:1.3,  radius:4.4},\n    front: {theta:0,     phi:1.571, radius:4.4},\n    top:   {theta:0,     phi:0.2,   radius:4.4},\n    right: {theta:1.571, phi:1.571, radius:4.4},\n  };\n  const viewToggle = document.getElementById('viewToggle');\n  const viewMenu = document.getElementById('viewMenu');\n  viewToggle.addEventListener('click', (e)=>{\n    e.stopPropagation();\n    const open = viewMenu.style.display !== 'none';\n    viewMenu.style.display = open ? 'none' : 'block';\n    viewToggle.classList.toggle('open', !open);\n  });\n  document.querySelectorAll('.view-menu button').forEach(btn=>{\n    btn.addEventListener('click', ()=>{\n      const preset = VIEW_PRESETS[btn.dataset.preset];\n      if(preset){ Object.assign(spherical, preset); target.set(0,0.1,0); updateCamera(); }\n      viewMenu.style.display = 'none';\n      viewToggle.classList.remove('open');\n    });\n  });\n  document.addEventListener('click', (e)=>{\n    if(!e.target.closest('.view-dropdown')){\n      viewMenu.style.display = 'none';\n      viewToggle.classList.remove('open');\n    }\n  });\n\n  // ---------- brightness ----------\n  document.getElementById('brightnessSlider').addEventListener('input', (e)=>{\n    setBrightness(parseFloat(e.target.value));\n  });\n\n  // ---------- part filter (vertical buttons) ----------\n  document.querySelectorAll('.part-filter-btn').forEach(btn=>{\n    btn.addEventListener('click', ()=>{\n      const parts = btn.dataset.parts.split(',');\n      const isSame = activePartFilter && activePartFilter.join(',') === parts.join(',');\n      document.querySelectorAll('.part-filter-btn').forEach(b=>b.classList.remove('active'));\n      if(isSame){\n        activePartFilter = null;\n      } else {\n        activePartFilter = parts;\n        btn.classList.add('active');\n      }\n      renderList();\n      renderPins();\n    });\n  });\n\n  // ---------- modal close / reopen ----------\n  const appEl = document.getElementById('app');\n  const reopenBtn = document.getElementById('reopenBtn');\n  document.getElementById('modalClose').addEventListener('click', ()=>{\n    appEl.style.display = 'none';\n    reopenBtn.style.display = 'flex';\n  });\n  reopenBtn.addEventListener('click', ()=>{\n    appEl.style.display = 'flex';\n    reopenBtn.style.display = 'none';\n    resize();\n  });\n\n  // ---------- boot ----------\n  resize();\n  loadComments();\n  loadRfqMeta();\n  animate();\n})();\n</script>\n</body>\n</html>\n"

/**
 * ProjectCard
 * A project summary card for a Framer site. Clicking it opens the full 3D viewer
 * (model + threaded, role-tagged comments) in a modal popup.
 *
 * @framerSupportedLayoutWidth any
 * @framerSupportedLayoutHeight any
 */
export default function ProjectCard(props) {
    const {
        title,
        rfqNumber,
        buyerName,
        description,
        accentColor,
        thumbnailEmoji,
    } = props

    const [open, setOpen] = useState(false)

    return (
        <>
            <div
                onClick={() => setOpen(true)}
                style={{
                    display: "flex",
                    flexDirection: "column",
                    width: "100%",
                    height: "100%",
                    background: "#FFFFFF",
                    borderRadius: 12,
                    overflow: "hidden",
                    cursor: "pointer",
                    boxShadow: "0px 1px 3px rgba(0,0,0,0.12)",
                    border: "1px solid #E4E8EC",
                    fontFamily:
                        "'Inter', -apple-system, BlinkMacSystemFont, sans-serif",
                    transition: "box-shadow 0.15s ease, transform 0.15s ease",
                }}
                onMouseEnter={(e) => {
                    e.currentTarget.style.boxShadow =
                        "0px 6px 20px rgba(0,0,0,0.14)"
                    e.currentTarget.style.transform = "translateY(-2px)"
                }}
                onMouseLeave={(e) => {
                    e.currentTarget.style.boxShadow =
                        "0px 1px 3px rgba(0,0,0,0.12)"
                    e.currentTarget.style.transform = "translateY(0)"
                }}
            >
                <div
                    style={{
                        height: 120,
                        flexShrink: 0,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        fontSize: 40,
                        background: `linear-gradient(135deg, ${accentColor}22, ${accentColor}0D)`,
                    }}
                >
                    {thumbnailEmoji}
                </div>
                <div
                    style={{
                        padding: "14px 16px 16px",
                        display: "flex",
                        flexDirection: "column",
                        gap: 6,
                        flex: 1,
                    }}
                >
                    <div
                        style={{
                            fontSize: 15,
                            fontWeight: 700,
                            color: "#1F2933",
                        }}
                    >
                        {title}
                    </div>
                    <div
                        style={{
                            fontSize: 11,
                            fontWeight: 600,
                            color: accentColor,
                        }}
                    >
                        RFQ #{rfqNumber} · {buyerName}
                    </div>
                    <div
                        style={{
                            fontSize: 12,
                            lineHeight: 1.4,
                            color: "#697786",
                            marginTop: 2,
                        }}
                    >
                        {description}
                    </div>
                    <div
                        style={{
                            marginTop: "auto",
                            paddingTop: 10,
                            fontSize: 11,
                            fontWeight: 600,
                            color: accentColor,
                            display: "flex",
                            alignItems: "center",
                            gap: 4,
                        }}
                    >
                        Open 3D viewer →
                    </div>
                </div>
            </div>

            {open && (
                <div
                    onClick={() => setOpen(false)}
                    style={{
                        position: "fixed",
                        inset: 0,
                        background: "rgba(20,24,31,0.6)",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        zIndex: 9999,
                    }}
                >
                    <div
                        onClick={(e) => e.stopPropagation()}
                        style={{
                            position: "relative",
                            width: "95vw",
                            maxWidth: 1500,
                            height: "90vh",
                            borderRadius: 16,
                            overflow: "hidden",
                            boxShadow: "0 24px 64px rgba(0,0,0,0.4)",
                        }}
                    >
                        <button
                            onClick={() => setOpen(false)}
                            aria-label="Close"
                            style={{
                                position: "absolute",
                                top: -14,
                                right: -14,
                                width: 32,
                                height: 32,
                                borderRadius: "50%",
                                border: "none",
                                background: "#fff",
                                boxShadow: "0px 0px 4px rgba(0,0,0,0.16)",
                                display: "flex",
                                alignItems: "center",
                                justifyContent: "center",
                                cursor: "pointer",
                                zIndex: 10,
                                fontSize: 16,
                                color: "#546881",
                            }}
                        >
                            ✕
                        </button>
                        <iframe
                            title="3D Viewer"
                            srcDoc={VIEWER_HTML}
                            style={{
                                width: "100%",
                                height: "100%",
                                border: "none",
                                borderRadius: 16,
                                background: "#F6F8F9",
                            }}
                        />
                    </div>
                </div>
            )}
        </>
    )
}

ProjectCard.defaultProps = {
    title: "Money Man",
    rfqNumber: "24815",
    buyerName: "Ascension Manufacturing",
    description:
        "Interactive 3D review with pinned, threaded comments for buyer/manufacturer collaboration.",
    accentColor: "#7636D9",
    thumbnailEmoji: "🎩",
}

addPropertyControls(ProjectCard, {
    title: { type: ControlType.String, title: "Title", defaultValue: "Money Man" },
    rfqNumber: { type: ControlType.String, title: "RFQ #", defaultValue: "24815" },
    buyerName: {
        type: ControlType.String,
        title: "Buyer",
        defaultValue: "Ascension Manufacturing",
    },
    description: {
        type: ControlType.String,
        title: "Description",
        defaultValue:
            "Interactive 3D review with pinned, threaded comments for buyer/manufacturer collaboration.",
        displayTextArea: true,
    },
    accentColor: {
        type: ControlType.Color,
        title: "Accent",
        defaultValue: "#7636D9",
    },
    thumbnailEmoji: {
        type: ControlType.String,
        title: "Thumbnail Icon",
        defaultValue: "🎩",
    },
})
